                  {/* Keyword rankings */}
                  {aiResult.analysis?.keyword_rankings?.length > 0 && (
                    <div className="rounded-xl border border-cyan-400/20 bg-cyan-400/5 p-4 mb-4">
                      <div className="text-xs font-mono text-cyan-400 uppercase tracking-wider mb-3">
