  useEffect(() => {
    import("@/lib/supabase").then(({ supabase }) => {
      supabase.from("projects").select("id,name").limit(20).then(({ data }) => {
        setProjects(data || []);
        if (data?.length) setSelProject(data[0].id);
      });
