                        background:`var(--accent-glow)`,border:`1px solid var(--border-glow)`,
                        display:"flex",alignItems:"center",justifyContent:"center",
                        fontSize:10,fontWeight:700,color:"hsl(var(--primary))"}}>
                        {i+1}
                      </div>
                      <div>
                        <div style={{fontSize:13,fontWeight:600,color:"hsl(var(--foreground))",marginBottom:2}}>{a.action}</div>
                        <div style={{fontSize:12,color:"hsl(var(--muted-foreground))"}}>{a.why}</div>
                      </div>
                      <span style={{marginLeft:"auto",flexShrink:0,fontSize:9,fontWeight:700,padding:"3px 8px",borderRadius:20,
