                      background:a.severity==="warning"?"rgba(245,158,11,.1)":a.severity==="critical"?"rgba(239,68,68,.1)":"hsl(var(--primary) / .2)",
                      color:a.severity==="warning"?"#f59e0b":a.severity==="critical"?"#f87171":"hsl(var(--primary))"}}>
