                ))}
                {!alerts.length&&<div style={{color:"hsl(var(--muted-foreground))",fontSize:12}}>No alerts. Everything is running smoothly. ✓</div>}
              </div>
            </div>
          )}

          {tab==="progress"&&(
            <div>
              <div style={{fontSize:12,color:"hsl(var(--muted-foreground))",marginBottom:16}}>
