                      return compHosts.some(c=>h===c||h.endsWith('.'+c));
                    };

                    // Group: own pages first, then competitors, then other
                    const sorted = [
                      ...allCachedPages.filter(p=>isOwn(p.url)),
                      ...allCachedPages.filter(p=>isComp(p.url)&&!isOwn(p.url)),
