                            title={full}
                          >
                            <Plus size={9}/>
                            <span className="truncate">{full.replace(/https?:\/\/[^/]+/,'').slice(0,25)||'/'}</span>
                          </button>
                        );
                      })}
                      {/* Competitors from knowledge */}
                      {['competitor_1','competitor_2','competitor_3'].map(key=>{
                        const comp = getField('competitor', key);
