                          </div>
                        );
                      })}
                      {crawlUrls.split(String.fromCharCode(10)).filter(Boolean).length>10 && <div className="text-xs text-orange-400 px-2 py-1">First 10 only</div>}
                    </div>
                  )}

                  {/* Load all known URLs if textarea is empty */}
