                  <Upload className="h-10 w-10 text-primary/30 mx-auto mb-3"/>
                  <h3 className="font-semibold mb-2">Upload SEO Reports & Exports</h3>
                  <p className="text-sm text-muted-foreground mb-4 max-w-md mx-auto">
