function AnimNum({v,prefix="",suffix=""}:{v:number,prefix?:string,suffix?:string}){
  const[d,setD]=useState(0);
  useEffect(()=>{
    const s=performance.now(),dur=600;
    const t=(now:number)=>{
      const p=Math.min((now-s)/dur,1);
